@namespace sv_104c0b4a03b649ba85ea121c4919a71b.Components.Pages.Board

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task)">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task)">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@namespace sv_104c0b4a03b649ba85ea121c4919a71b.Components.Pages.Board

<div class="card border-primary mt-2">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@saving">
                @(saving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-secondary btn-sm" @onclick="HandleCancel" disabled="@saving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        saving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        finally
        {
            saving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@namespace sv_104c0b4a03b649ba85ea121c4919a71b.Components.Pages.Board

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@namespace sv_104c0b4a03b649ba85ea121c4919a71b.Components.Pages.Board

<div class="col-md-4">
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="HandleMoveLeft"
                          OnMoveRight="HandleMoveRight" />
            }

            @if (showForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="HandleCancel" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100 mt-2" @onclick="() => showForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(TaskItem Task, string Direction)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleMoveLeft(TaskItem task)
    {
        await OnTaskMoved.InvokeAsync((task, "left"));
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        await OnTaskMoved.InvokeAsync((task, "right"));
    }

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnTaskCreated.InvokeAsync(data);
        showForm = false;
    }

    private void HandleCancel()
    {
        showForm = false;
    }
}

@page "/board"
@namespace sv_104c0b4a03b649ba85ea121c4919a71b.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="tasks" />
    <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="GetFilteredTasks("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="data => HandleTaskCreated(data, "To Do")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="GetFilteredTasks("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="data => HandleTaskCreated(data, "In Progress")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="GetFilteredTasks("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="data => HandleTaskCreated(data, "Done")" />
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> tasks = new();
    private string searchTerm = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private void HandleSearchChanged(string term)
    {
        searchTerm = term;
    }

    private async Task HandleTaskMoved((TaskItem Task, string Direction) move)
    {
        var currentIndex = Array.IndexOf(Columns, move.Task.Status);
        var newIndex = move.Direction == "left" ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= Columns.Length) return;

        var newStatus = Columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.Task.Id, newStatus);
            var index = tasks.FindIndex(t => t.Id == move.Task.Id);
            if (index >= 0)
            {
                tasks[index] = move.Task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            // The service may return the task with a default status; ensure it matches the column
            if (newTask.Status != status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, status);
                newTask = newTask with { Status = status };
            }
            tasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

